// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract Enum {
//     • 任务：编写一个Solidity智能合约，实现一个简单的订单处理系统。
//         ◦ 声明一个名为 OrderStatus 的枚举，包括状态： None , Pending , Shipped ,
//         Completed , Rejected , Cancelled 。
//         ◦ 创建一个结构体 Order ，包含买家地址和订单状态。
//         ◦ 实现功能：
//         i. 添加新订单到数组。
//         ii. 更新订单状态。
//         iii. 获取特定订单的状态。
//         iv. 重置订单状态到默认值。
    enum OrderStatus {
        None,
        Pending,
        Shipped,
        Completed,
        Rejected,
        Cancelled
    }

    OrderStatus public status; //默认为None

    struct Order {
        address buyer;
        OrderStatus status;
    }

    Order[] public  orders;

    function add(Order memory order) external {
        orders.push(order);
    }

    function setStatus(OrderStatus newStatus) external {
        status = newStatus;
    }

    function getStatus() external view returns(OrderStatus){
       return status;
    }

    function reset() external {
        delete status;
    }
}


// 创建一个Solidity智能合约，名为 MessageStore ，包含以下功能：
// • 一个公开的状态变量 message 用于存储一个字符串。
// • 一个 setMessage 函数，允许用户输入一个字符串并将其存储到 message 状态变量中。该函数 应使用calldata数据位置。
// • 一个 getMessage 函数，返回 message 状态变量的内容。该函数应声明为external，并使用 memory数据位置。
contract MessageStore {
    string public message;

    function setMessage(string calldata newMsg) external {
        message = newMsg;
    }

    function getMessage() external view returns(string memory){
        return message;
    }
}

